import React from "react";
import styled from "styled-components";
import ColorScheme from "color-scheme";

import ContentParent from "./content_parent";
import IntroPanel from "./intro";
import WorkPanel from "./work";
import ProjectsPanel from "./projects";
import AboutPanel from "./about";
import Footer from "./footer";

import ColorButton from "./color_button";
// TODO import ScrollButton from "./scroll_to_top";

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      colors: {
        main: "#ffffff",
        panel: "#e6e6e6",
        button_border: "#474747",
        button_text: "#212121",
        heading: "#212121",
        text: "#1c1c1c",
        text_highlight: "#212121",
      },
    };
  }

  componentDidMount() {
    document.addEventListener("keydown", (e) => {
      if (e.key == " ") {
        e.preventDefault();
        this.randomizeColors(e);
      }
    });
  }
  a;

  componentWillUnmount() {
    window.removeEventListener("keydown", (e) => {
      if (e.key === 32) {
        e.preventDefault();
        this.randomizeColors(e);
      }
    });
  }

  randomizeColors = (e) => {
    e.preventDefault();

    let schemes = ["contrast", "triade", "tetrade"];
    let randomScheme = schemes[Math.floor(Math.random() * schemes.length)];

    let randomHue = Math.floor(Math.random() * 360);

    let colorScheme = new ColorScheme()
      .from_hue(randomHue)
      .scheme(randomScheme)
      .variation("default");
    colorScheme.from_hue(randomHue).scheme(randomScheme).variation("default");

    let randomColors = colorScheme.colors().map((hex) => "#" + hex);

    let bgColors = randomColors.slice(0, 4);
    let textColors = randomColors.slice(4, 8);

    // These indices have been hand-picked as they come in a certain hue order
    // and some combinations have better contrast than others
    this.setState({
      colors: {
        main: bgColors[0],
        panel: bgColors[1],
        button_border: bgColors[3],
        button_text: textColors[0],
        heading: textColors[0],
        text: textColors[2],
        text_highlight: textColors[0],
      },
    });
  };

  render() {
    return (
      <ContentParent colors={this.state.colors}>
        <ColorButton clickHandler={this.randomizeColors} />
        <IntroPanel />
        <AboutPanel />
        <WorkPanel />
        <ProjectsPanel />
        <Footer />
      </ContentParent>
    );
  }
}

export default App;

const MainContainer = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  height: 100%;
  width: 100%;
  background: ${(props) => props.color};
  transition: all 0.8s ease-in;
  * {
    transition: all 0.8s ease-in;
  }
`;
